B.ae7=new A.bj("\u2022 Typujemy wyniki mecz\xf3w w regulaminowym czasie gry.\n\u2022 W fazie pucharowej dodatkowo wybieramy dru\u017cyn\u0119, kt\xf3ra awansuje dalej.",null,null,null,null,null,null,null,null)
B.hV=new A.cT(null,12,null,null)
B.aek=new A.bj("Punktacja - Faza Grupowa:",null,B.cC,null,null,null,null,null,null)
B.aew=new A.bj("\u2022 Dok\u0142adny wynik: 5 pkt\n\u2022 Rozstrzygni\u0119cie i r\xf3\u017cnica bramek: 2 pkt\n\u2022 Tylko rozstrzygni\u0119cie (zwyci\u0119zca/remis): 1 pkt",null,null,null,null,null,null,null,null)
B.aeK=new A.bj("Punktacja - Faza Pucharowa:",null,B.cC,null,null,null,null,null,null)
B.aeA=new A.bj("\u2022 Wyb\xf3r zwyci\u0119zcy (awans): 2 pkt\n\u2022 Dok\u0142adny wynik (90 min): 4 pkt\n\u2022 Mo\u017cliwe zdobycie \u0142\u0105cznie 6 pkt za mecz.",null,null,null,null,null,null,null,null)
B.aeh=new A.bj("Typy D\u0142ugoterminowe:",null,B.cC,null,null,null,null,null,null)
B.aeg=new A.bj("\u2022 Trafienie Mistrza: 15 pkt\n\u2022 Trafienie Kr\xf3la Strzelc\xf3w: 10 pkt\n\u2022 Kr\xf3l strzelc\xf3w: brak mo\u017cliwo\u015bci zmiany po rozpocz\u0119ciu turnieju.\n\u2022 Mistrz: zmiana mo\u017cliwa do startu fazy pucharowej. Pierwsza zmiana kosztuje 5 pkt (odejmowane jednorazowo), kolejne zmiany s\u0105 bezp\u0142atne.",null,null,null,null,null,null,null,null)
