B.aeF=new A.bj("Zasady Rozstrzygania Remis\xf3w (Ex Aequo):",null,B.cC,null,null,null,null,null,null)
B.aeQ=new A.bj("W przypadku uzyskania przez kilku uczestnik\xf3w tej samej liczby punkt\xf3w, nagrody przewidziane dla zajmowanych przez nich miejsc s\u0105 sumowane i dzielone po r\xf3wno pomi\u0119dzy tych uczestnik\xf3w.\n\nPrzyk\u0142ad: Je\u015bli 3 osoby zajm\u0105 ex aequo 1. miejsce:\n\u2022 \u0141\u0105czy si\u0119 nagrody za 1., 2. i 3. miejsce (np. 50% + 30% + 20% = 100% puli).\n\u2022 Ca\u0142a kwota jest dzielona po r\xf3wno na te 3 osoby.\n\u2022 W takim przypadku nie przyznaje si\u0119 ju\u017c oddzielnie 2. i 3. miejsca.",null,null,null,null,null,null,null,null)
